mapper.select:
SELECT od.name as name,IFNULL(count(od.number), 0) AS turnover FROM order_detail od left join orders o on o.id = od.order_id
AND o.order_time > CONCAT(#{begin}, ' 00:00:00') AND o.order_time < CONCAT(#{end}, ' 23:59:59') AND o.status = #{status}
GROUP BY od.name ORDER BY turnover DESC LIMIT 10
